import { AsyncStorage } from 'react-native';
import CryptoJS from 'crypto-js';

const ENCRYPTION_KEY = 'YOUR_ENCRYPTION_KEY';

export const encryptData = (data) => {
  return CryptoJS.AES.encrypt(JSON.stringify(data), ENCRYPTION_KEY).toString();
};

export const decryptData = (data) => {
  return JSON.parse(CryptoJS.AES.decrypt(data, ENCRYPTION_KEY));
};

const saveUserProfile = async (profile) => {
  await AsyncStorage.setItem('userProfile', encryptData(profile));
};

const getUserProfile = async () => {
  const encryptedProfile = await AsyncStorage.getItem('userProfile');
  return decryptData(encryptedProfile);
};